import{_ as t,o as a,c,a4 as d}from"./chunks/framework.Cqne-ChA.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-update-cacert.md","filePath":"reference/zopen-update-cacert.md","lastUpdated":1776692264000}'),r={name:"reference/zopen-update-cacert.md"};function p(n,e,i,l,o,s){return a(),c("div",null,[...e[0]||(e[0]=[d('<div class="man-page-content" data-v-ce30cdc2><h1 align="center" data-v-ce30cdc2>ZOPEN-UPDATE-CACERT</h1><h2 data-v-ce30cdc2>NAME <a name="NAME" data-v-ce30cdc2></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2>zopen-update-cacert − manual page for zopen-update-cacert 0.8.4</p><h2 data-v-ce30cdc2>DESCRIPTION <a name="DESCRIPTION" data-v-ce30cdc2></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2>zopen−update−cacert: Update your cacert.pem file to the latest CA certificates extracted from Mozilla.</p><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2><b data-v-ce30cdc2>Syntax:</b></p><p style="margin-left:22%;" data-v-ce30cdc2>zopen−update−cacert [−fhv] [&lt;directory&gt;]</p><h2 data-v-ce30cdc2>OPTIONS <a name="OPTIONS" data-v-ce30cdc2></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2><b data-v-ce30cdc2>−f</b>, <b data-v-ce30cdc2>−−force</b></p><p style="margin-left:22%;" data-v-ce30cdc2>update cacert.pem file even if up to date.</p><p style="margin-left:11%;" data-v-ce30cdc2><b data-v-ce30cdc2>−h</b>, <b data-v-ce30cdc2>−−help</b></p><p style="margin-left:22%;" data-v-ce30cdc2>print this help.</p><p style="margin-left:11%;" data-v-ce30cdc2><b data-v-ce30cdc2>−i</b>, <b data-v-ce30cdc2>−−insecure−fallback</b></p><p style="margin-left:22%;" data-v-ce30cdc2>(UNSAFE) Skip certificate validation during download.</p><p style="margin-left:11%;" data-v-ce30cdc2><b data-v-ce30cdc2>−v</b>, <b data-v-ce30cdc2>−−verbose</b></p><p style="margin-left:22%;" data-v-ce30cdc2>print verbose messages.</p><p style="margin-left:11%;" data-v-ce30cdc2><b data-v-ce30cdc2>−−version</b></p><p style="margin-left:22%;" data-v-ce30cdc2>print version.</p><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2><b data-v-ce30cdc2>Parameters:</b></p><p style="margin-left:22%;" data-v-ce30cdc2>&lt;directory&gt;: the directory where the cacert.pem will be updated.</p><p style="margin-left:22%;margin-top:1em;" data-v-ce30cdc2>The default directory location is: <i data-v-ce30cdc2>/var/lib/jenkins/workspace/Port−Update−Nightly/meta_update</i></p><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2>This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p><h2 data-v-ce30cdc2>AUTHOR <a name="AUTHOR" data-v-ce30cdc2></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-ce30cdc2>Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p></div>',1)])])}const f=t(r,[["render",p],["__scopeId","data-v-ce30cdc2"]]);export{v as __pageData,f as default};
